package com.hospital.management.model;/** String-backed medicine item form. */public class PrescriptionItemForm {private Long prescriptionItemId;private String medicineName,dosage,frequency,duration,route,instructions;public Long getPrescriptionItemId(){return prescriptionItemId;}public void setPrescriptionItemId(Long v){prescriptionItemId=v;}public String getMedicineName(){return medicineName;}public void setMedicineName(String v){medicineName=v;}public String getDosage(){return dosage;}public void setDosage(String v){dosage=v;}public String getFrequency(){return frequency;}public void setFrequency(String v){frequency=v;}public String getDuration(){return duration;}public void setDuration(String v){duration=v;}public String getRoute(){return route;}public void setRoute(String v){route=v;}public String getInstructions(){return instructions;}public void setInstructions(String v){instructions=v;}}
